Model *Model::fromMesh(Mesh *mesh, Material material) {
    Model *newModel = new Model();
    std::vector<RenderMesh> meshes;
    meshes.push_back(*(new RenderMesh(mesh, material)));
    newModel->meshes = meshes;
    return newModel;
}
